import { NextRequest, NextResponse } from 'next/server'
import { getAllRuns } from '@/lib/runs'
import { filterRuns, type QueryFilters } from '@/lib/export'
import { validateAuth, authResponse } from '@/lib/api-auth'

export async function GET(request: NextRequest) {
  const authResult = await validateAuth(request)
  if (!authResult.allowed) {
    return authResponse(authResult.error!, authResult.status!)
  }

  try {
    const runs = await getAllRuns()
    const { searchParams } = request.nextUrl

    const filters: QueryFilters = {}
    if (searchParams.get('model')) filters.model = searchParams.get('model')!
    if (searchParams.get('task')) filters.task = searchParams.get('task')!
    if (searchParams.get('startDate')) filters.startDate = searchParams.get('startDate')!
    if (searchParams.get('endDate')) filters.endDate = searchParams.get('endDate')!
    if (searchParams.get('minScore')) filters.minScore = parseFloat(searchParams.get('minScore')!)
    if (searchParams.get('maxScore')) filters.maxScore = parseFloat(searchParams.get('maxScore')!)
    if (searchParams.get('datasetVersion')) filters.datasetVersion = searchParams.get('datasetVersion')!

    const filtered = filterRuns(runs, filters)

    const limitParam = searchParams.get('limit')
    const offsetParam = searchParams.get('offset')

    if (limitParam !== null || offsetParam !== null) {
      const limit = limitParam ? parseInt(limitParam, 10) : filtered.length
      const offset = offsetParam ? parseInt(offsetParam, 10) : 0

      const paged = filtered.slice(offset, offset + limit)

      return NextResponse.json({
        count: paged.length,
        runs: paged,
        total: filtered.length,
        limit,
        offset,
      })
    }

    return NextResponse.json({
      count: filtered.length,
      runs: filtered,
    })
  } catch {
    return NextResponse.json({ error: 'Failed to fetch runs' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { getRunById } from '@/lib/runs'
import { validateAuth, authResponse } from '@/lib/api-auth'

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const authResult = await validateAuth(request)
  if (!authResult.allowed) {
    return authResponse(authResult.error!, authResult.status!)
  }

  try {
    const { id } = await params
    const run = await getRunById(id)

    if (!run) {
      return NextResponse.json({ error: 'Run not found' }, { status: 404 })
    }

    return NextResponse.json(run)
  } catch {
    return NextResponse.json({ error: 'Failed to fetch run' }, { status: 500 })
  }
}

