import { NextRequest, NextResponse } from 'next/server'
import { getAllRuns } from '@/lib/runs'
import { filterRuns, runsToLeaderboardFormat, type QueryFilters } from '@/lib/export'
import { validateAuth, authResponse } from '@/lib/api-auth'

export async function GET(request: NextRequest) {
  const authResult = await validateAuth(request)
  if (!authResult.allowed) {
    return authResponse(authResult.error!, authResult.status!)
  }

  try {
    const runs = await getAllRuns()
    const { searchParams } = request.nextUrl

    const filters: QueryFilters = {}
    if (searchParams.get('model')) filters.model = searchParams.get('model')!

    let filtered = filterRuns(runs, filters)

    const provider = searchParams.get('provider')
    if (provider) {
      filtered = filtered.filter(r => r.provider === provider)
    }

    const leaderboard = runsToLeaderboardFormat(filtered)
    leaderboard.sort((a, b) => b.meanScore - a.meanScore)

    return NextResponse.json({
      count: leaderboard.length,
      leaderboard,
    })
  } catch {
    return NextResponse.json({ error: 'Failed to fetch leaderboard' }, { status: 500 })
